const user = {
  name: 'Deiva',
  age: 30,
  active: true,
  address: {             // nested object
    city: 'Chennai',
    country: 'India',
  },
  greet() {              // shorthand method
    return `Hello, ${this.name}`;
  },
};

// Computed property names
const key = 'score';
const stats = { [key]: 95, [`${key}_label`]: 'A+' };

const animalProto = {
  breathe() { return `${this.name} breathes`; },
};

const cat = Object.create(animalProto);
cat.name = 'Whiskers';
cat.breathe();   // "Whiskers breathes"

// Null prototype — no inherited methods at all (useful for pure maps)
const safeMap = Object.create(null);
safeMap.key = 'value';
// safeMap.toString  // undefined — no Object.prototype

class Point {
  constructor(
    public x: number,
    public y: number,
  ) {}

  distanceTo(other: Point): number {
    const dx = this.x - other.x;
    const dy = this.y - other.y;
    return Math.sqrt(dx * dx + dy * dy);
  }

  toString(): string {
    return `(${this.x}, ${this.y})`;
  }
}

const a = new Point(0, 0);
const b = new Point(3, 4);
a.distanceTo(b);   // 5

const obj = { name: 'Deiva', 'data-id': 42, score: 98 };

// Dot notation
obj.name;              // 'Deiva'
obj.name = 'Ana';     // write

// Bracket notation (required for special chars or dynamic keys)
obj['data-id'];        // 42
const key = 'score';
obj[key];              // 98

// Optional chaining — safe access on possibly-undefined
const user: { address?: { city?: string } } = {};
user?.address?.city;   // undefined (no throw)

// Non-existent property → undefined, not an error
obj.missing;           // undefined

const obj = { a: 1, b: undefined };

// in — checks own AND inherited
'a' in obj;                    // true
'toString' in obj;             // true (inherited)

// hasOwn — own properties only (ES2022, replaces hasOwnProperty)
Object.hasOwn(obj, 'a');       // true
Object.hasOwn(obj, 'toString'); // false

// typeof check — also catches undeclared variables
typeof obj.missing === 'undefined';  // true

// delete removes a property entirely (vs. setting to undefined)
delete obj.a;
Object.hasOwn(obj, 'a');  // false

const scores = { alice: 92, bob: 87, carol: 95 };

// keys
Object.keys(scores);     // ['alice', 'bob', 'carol']

// values
Object.values(scores);   // [92, 87, 95]

// entries (pairs)
for (const [name, score] of Object.entries(scores)) {
  console.log(`${name}: ${score}`);
}
// alice: 92
// bob: 87
// carol: 95

// Convert to Map for O(1) lookups
const scoreMap = new Map(Object.entries(scores));

const user = { name: 'Deiva', age: 30, role: 'admin', active: true };

// Basic
const { name, age } = user;

// Rename
const { name: userName, role: userRole } = user;

// Default value (used when property is undefined)
const { theme = 'dark' } = user;    // 'dark' — user.theme is undefined

// Nested
const config = { db: { host: 'localhost', port: 5432 } };
const { db: { host, port } } = config;

// Rest — remaining props
const { name: n, ...rest } = user;
// rest = { age: 30, role: 'admin', active: true }

// In function parameters — very common in Angular
function render({ title, subtitle = 'No subtitle' }: { title: string; subtitle?: string }) {
  return `${title} — ${subtitle}`;
}

const original = { name: 'Deiva', scores: [92, 87] };

// Spread (ES2018)
const copy1 = { ...original };
copy1.name = 'Ana';          // does not affect original.name

// But nested references are shared:
copy1.scores.push(99);       // original.scores is now [92, 87, 99] — same array!

// Object.assign is equivalent for shallow copy
const copy2 = Object.assign({}, original);

const original = { name: 'Deiva', scores: [92, 87], meta: { active: true } };

// structuredClone (ES2021) — deep copy with no shared references
const deep = structuredClone(original);
deep.scores.push(99);        // original.scores is still [92, 87]
deep.meta.active = false;    // original.meta.active is still true

// structuredClone does NOT copy functions, class instances, or DOM nodes
// For those, use a serialization library or write a custom copy

@Component({
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class UserCardComponent {
  @Input() user!: User;
}

// Parent — create a NEW object reference; mutation would be missed:
updateUser(patch: Partial<User>) {
  this.user = { ...this.user, ...patch };  // ✓ new reference → OnPush detects change
  // this.user.name = 'X';                // ✗ mutation — OnPush misses it
}

const config = {};

Object.defineProperty(config, 'MAX_RETRIES', {
  value: 3,
  writable: false,       // assignment is silently ignored (throws in strict mode)
  enumerable: true,      // appears in Object.keys()
  configurable: false,   // cannot be redefined or deleted
});

config.MAX_RETRIES = 10; // silently ignored (or TypeError in strict)
config.MAX_RETRIES;      // still 3

// Object.freeze makes ALL properties writable:false + configurable:false
const DEFAULTS = Object.freeze({ timeout: 5000, retries: 3 });
// DEFAULTS.timeout = 9999; // no effect

interface Product {
  id: number;
  name: string;
  price: number;
  category: string;
}

@Component({
  selector: 'app-product-card',
  template: `
    <h3>{{ product.name }}</h3>
    <p>{{ product.price | currency }}</p>
    <span>{{ product.category }}</span>
  `,
})
export class ProductCardComponent {
  @Input() product!: Product;
}

@Injectable({ providedIn: 'root' })
export class CartService {
  // Shared object state across the app
  private state = {
    items: [] as CartItem[],
    discount: 0,
  };

  addItem(item: CartItem) {
    this.state = {
      ...this.state,                          // spread to new object
      items: [...this.state.items, item],
    };
  }

  get total() {
    return this.state.items.reduce((sum, i) => sum + i.price, 0)
      * (1 - this.state.discount);
  }
}

const prices = { apple: 1.5, banana: 0.8, cherry: 3.2 };

// Transform values — multiply all prices by 1.1
const increased = Object.fromEntries(
  Object.entries(prices).map(([k, v]) => [k, +(v * 1.1).toFixed(2)])
);
// { apple: 1.65, banana: 0.88, cherry: 3.52 }

// Filter properties
const expensive = Object.fromEntries(
  Object.entries(prices).filter(([, v]) => v > 1.0)
);
// { apple: 1.5, cherry: 3.2 }

// Merge multiple sources (left-to-right — later sources win)
const defaults = { timeout: 3000, retries: 2, debug: false };
const userConfig = { retries: 5, debug: true };

const config = Object.assign({}, defaults, userConfig);
// { timeout: 3000, retries: 5, debug: true }

// Spread equivalent (cleaner syntax)
const config2 = { ...defaults, ...userConfig };

function isEmpty(obj: object): boolean {
  return Object.keys(obj).length === 0;
}

isEmpty({});              // true
isEmpty({ a: 1 });        // false

// Count properties
const propertyCount = Object.keys(user).length;

class Animal {
  constructor(public name: string) {}
  speak() { return `${this.name} makes a sound`; }
}

class Dog extends Animal {
  bark() { return `${this.name} barks`; }
}

const rex = new Dog('Rex');

// Chain: rex → Dog.prototype → Animal.prototype → Object.prototype → null

rex.bark();              // own method on Dog.prototype
rex.speak();             // found on Animal.prototype
rex.toString();          // found on Object.prototype

// Inspect the chain
Object.getPrototypeOf(rex) === Dog.prototype;           // true
Object.getPrototypeOf(Dog.prototype) === Animal.prototype; // true

// instanceof walks the chain
rex instanceof Dog;      // true
rex instanceof Animal;   // true
rex instanceof Object;   // true

const id = Symbol('id');
const meta = Symbol('meta');

const user = {
  name: 'Deiva',
  [id]: 123,                // Symbol key — won't show in Object.keys
  [meta]: { version: 2 },
};

user[id];                   // 123
Object.keys(user);          // ['name']
JSON.stringify(user);       // '{"name":"Deiva"}' — Symbols excluded

// Retrieve symbol keys explicitly
Object.getOwnPropertySymbols(user);  // [Symbol(id), Symbol(meta)]

class Rectangle {
  constructor(
    private _width: number,
    private _height: number,
  ) {}

  get area(): number {
    return this._width * this._height;
  }

  get width(): number { return this._width; }
  set width(value: number) {
    if (value <= 0) throw new RangeError('Width must be positive');
    this._width = value;
  }
}

const rect = new Rectangle(4, 5);
rect.area;          // 20 — computed, not stored
rect.width = 10;    // calls setter with validation
rect.area;          // 50
